import Image from 'next/image';
import AccordionButtons from './AccordionButtons';

interface AccordionItemsProps {
  title: string;
  hasImage?: true;
  imageUrl?: string;
  identifier: string;
}

export default function AccordionItems({
  title,
  hasImage,
  imageUrl,
  identifier
}: AccordionItemsProps) {
  return (
    <div className="mb-4 flex flex-col items-center justify-between gap-2 md:flex-row lg:px-10">
      <div className="flex items-center gap-2 md:gap-4">
        {hasImage && (
          <Image
            className="md:scale-120"
            src={imageUrl!}
            alt={title}
            width={30}
            height={30}
          />
        )}
        <h3 className='lg:text-3xl'>{title}</h3>
      </div>
      <AccordionButtons identifier={identifier} />
    </div>
  );
}
